import hashlib
from dataclasses import dataclass

@dataclass
class Flag:
    name: str
    enabled: bool
    rollout: float = 1.0

class FlagEvaluator:
    def __init__(self, flags: dict[str, Flag]) -> None:
        self.flags = flags

    def is_enabled(self, name: str, user_id: str) -> bool:
        flag = self.flags.get(name)
